import axios from 'axios';
import toast from 'react-hot-toast';

// Function to find backend port
async function findBackendPort() {
  const commonPorts = [5001, 5002, 5003, 5004, 5005, 5000, 3001, 8001];

  for (const port of commonPorts) {
    try {
      const response = await axios.get(`http://localhost:${port}/api/health`, { timeout: 2000 });
      if (response.status === 200) {
        console.log(`✅ Backend found on port ${port}`);
        return port;
      }
    } catch (error) {
      // Port not available, try next
      continue;
    }
  }

  // Fallback to default
  console.warn('⚠️  Could not find backend automatically, using default port 5001');
  return 5001;
}

// Initialize API with dynamic port detection
let API_URL;
let api;

async function initializeApi() {
  const port = await findBackendPort();
  API_URL = `http://localhost:${port}/api`;

  api = axios.create({
    baseURL: API_URL,
    headers: {
      'Content-Type': 'application/json',
    },
    timeout: 30000, // 30 seconds
  });

  // Request interceptor
  api.interceptors.request.use(
    (config) => {
      const token = localStorage.getItem('token');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      return config;
    },
    (error) => {
      return Promise.reject(error);
    }
  );

  // Response interceptor
  api.interceptors.response.use(
    (response) => response,
    (error) => {
      if (error.code === 'ECONNABORTED') {
        toast.error('Request timeout. Please try again.');
      } else if (error.response) {
        const { status, data } = error.response;
        if (status === 401) {
          localStorage.removeItem('token');
          localStorage.removeItem('user');
          window.location.href = '/login';
          toast.error('Session expired. Please login again.');
        } else if (status === 403) {
          toast.error('You do not have permission to perform this action.');
        } else if (status === 404) {
          toast.error('Resource not found.');
        } else if (status >= 500) {
          toast.error('Server error. Please try again later.');
        } else if (data && data.message) {
          toast.error(data.message);
        }
      } else if (error.request) {
        toast.error('Network error. Please check your connection.');
      } else {
        toast.error('An unexpected error occurred.');
      }
      return Promise.reject(error);
    }
  );
}

// Initialize the API
initializeApi();

// Export the api instance (will be available after initialization)
export { api, API_URL };
export default api;
